  1 //! Burn-in: teach the assistant a codebase in one pass.
  2 //!
  3 //! `ciabatta ai burn-in` traverses the project and builds the architecture
  4 //! mind map without waiting for questions to trickle knowledge in:
  5 //!
  6 //!   1. **Survey** — the model sees the file tree plus the heads of the
  7 //!      README/manifests and names the project's architecture parts (each
  8 //!      with a one-line description).
  9 //!   2. **Traverse** — source files go to the model in batches (path + the
 10 //!      first lines of each); it tags every file into one or more of those
 11 //!      architectures.
 12 //!
 13 //! Tags apply to the map immediately by default (watch them appear live on
 14 //! the mind-map page); with `--review` they queue as pending proposals
 15 //! instead, rendered as ghost nodes until you accept or reject them.
 16 
 17 use std::io::Read;
 18 use std::path::Path;
 19 use std::sync::Arc;
 20 
 21 use anyhow::{Context, Result};
 22 use serde_json::Value;
 23 use tokio::sync::mpsc;
 24 
 25 use super::provider::Turn;
 26 use super::{AiEvent, Assistant, server, tools};
 27 
 28 /// Files per model request. Big enough to amortize the round trip, small
 29 /// enough that every file's head fits comfortably.
 30 const BATCH_SIZE: usize = 15;
 31 /// How much of each file the model sees.
 32 const HEAD_LINES: usize = 30;
 33 const HEAD_BYTES: usize = 1600;
 34 /// Cap on the paths listed in the survey prompt.
 35 const SURVEY_PATHS: usize = 500;
 36 
 37 /// Run the burn-in from the CLI: spawn the live map, stream progress to
 38 /// stdout, then keep the map up until Ctrl-C so the result can be explored.
 39 pub async fn run(
 40     assistant: Arc<Assistant>,
 41     root: &Path,
 42     port: u16,
 43     review: bool,
 44     limit: Option<usize>,
 45 ) -> Result<()> {
 46     let jobs = super::jobs::Jobs::open(root, &assistant.toolbox.config)?;
 47     let url = server::spawn(assistant.clone(), jobs, port).await?;
 48     println!("🔥 Burn-in: teaching the assistant this codebase");
 49     println!("   provider: {}", assistant.provider.label());
 50     println!("   live map: {url}");
 51     println!("   mode:     {}\n", if review {
 52         "review — tags wait for your confirmation (ghosts on the map)"
 53     } else {
 54         "apply — tags land on the map as they're determined"
 55     });
 56 
 57     // Drain the burn's progress events to stdout while it runs.
 58     let (tx, mut rx) = mpsc::channel::<AiEvent>(64);
 59     let printer = tokio::spawn(async move {
 60         while let Some(ev) = rx.recv().await {
 61             if let AiEvent::Status(s) = ev {
 62                 println!("  {s}");
 63             }
 64         }
 65     });
 66 
 67     let summary = burn_core(&assistant, root, review, limit, &tx).await;
 68     drop(tx);
 69     let _ = printer.await;
 70     let summary = summary?;
 71 
 72     println!("\n{summary}");
 73     println!("\nThe map stays live at {url} — press Ctrl-C to finish.");
 74     tokio::signal::ctrl_c().await?;
 75     Ok(())
 76 }
