 78 /// The burn-in itself: survey the project, then tag every source file batch by
 79 /// batch, streaming human-readable progress as `AiEvent::Status`. Returns a
 80 /// final summary line. Shared by the CLI (`run`) and the chat `/burn` command,
 81 /// neither of which this function assumes — it spawns no server and never
 82 /// blocks on Ctrl-C.
 83 pub async fn burn_core(
 84     assistant: &Assistant,
 85     root: &Path,
 86     review: bool,
 87     limit: Option<usize>,
 88     events: &mpsc::Sender<AiEvent>,
 89 ) -> Result<String> {
 90     let mut files = source_files(root);
 91     if let Some(n) = limit {
 92         files.truncate(n);
 93     }
 94     anyhow::ensure!(
 95         !files.is_empty(),
 96         "no source files found under {} to analyze",
 97         root.display()
 98     );
 99 
100     // ── 0. static analysis: fold the dependency graph into the knowledge map ─
101     match scan_dependencies(assistant, root, events).await {
102         Ok(summary) => {
103             let _ = events.send(AiEvent::Status(summary)).await;
104         }
105         Err(e) => {
106             let _ = events
107                 .send(AiEvent::Status(format!("dependency scan skipped ({e})")))
108                 .await;
109         }
110     }
111 
112     // ── 1. survey: name the architecture parts ──────────────────────────────
113     assistant.set_activity(Some(format!(
114         "burn-in: surveying the project layout ({} files)",
115         files.len()
116     )));
117     let _ = events
118         .send(AiEvent::Status(format!(
119             "surveying the project layout ({} files)…",
120             files.len()
121         )))
122         .await;
123     match survey(assistant, root, &files).await {
124         Ok(arches) => {
125             for (name, description) in &arches {
126                 assistant.brain.set_architecture(name, description)?;
127                 let _ = events
128                     .send(AiEvent::Status(format!("◆ {name} — {description}")))
129                     .await;
130             }
131         }
132         // The survey improves tag consistency but isn't load-bearing: the
133         // traversal can still mint architecture names on its own.
134         Err(e) => {
135             let _ = events
136                 .send(AiEvent::Status(format!(
137                     "survey failed ({e}) — continuing with per-file tagging"
138                 )))
139                 .await;
140         }
141     }
142 
143     // ── 2. traverse: tag every file, batch by batch ─────────────────────────
144     let total_batches = files.len().div_ceil(BATCH_SIZE);
145     let _ = events
146         .send(AiEvent::Status(format!(
147             "tagging {} files in {total_batches} batches…",
148             files.len()
149         )))
150         .await;
151     let mut tagged = 0usize;
152     let mut failed_batches = 0usize;
153     for (i, batch) in files.chunks(BATCH_SIZE).enumerate() {
154         assistant.set_activity(Some(format!(
155             "burn-in: analyzing files {}–{} of {}",
156             i * BATCH_SIZE + 1,
157             (i * BATCH_SIZE + batch.len()),
158             files.len()
159         )));
160         match tag_batch(assistant, root, batch, review).await {
161             Ok(n) => {
162                 tagged += n;
163                 let _ = events
164                     .send(AiEvent::Status(format!(
165                         "[{}/{total_batches}] {} → {n} tagged",
166                         i + 1,
167                         batch[0]
168                     )))
169                     .await;
170             }
171             Err(e) => {
172                 failed_batches += 1;
173                 let _ = events
174                     .send(AiEvent::Status(format!(
175                         "[{}/{total_batches}] batch failed: {e}",
176                         i + 1
177                     )))
178                     .await;
179             }
180         }
181     }
182     assistant.set_activity(None);
183 
184     // ── summary ─────────────────────────────────────────────────────────────
185     let arch_count = assistant.brain.graph_json()["nodes"]
186         .as_array()
187         .map(|n| n.iter().filter(|v| v["kind"] == "architecture").count())
188         .unwrap_or(0);
189     let mut summary = format!(
190         "Burn-in complete: {tagged} of {} files tagged across {arch_count} architectures{}.",
191         files.len(),
192         if failed_batches > 0 {
193             format!(" ({failed_batches} batch(es) failed)")
194         } else {
195             String::new()
196         }
197     );
198     if review {
199         let pending = assistant.brain.pending().len();
200         summary.push_str(&format!(
201             "\n{pending} tag proposal(s) await review — accept or reject them on the map \
202              or with Ctrl-Y / Ctrl-N."
203         ));
204     }
205     Ok(summary)
206 }
