208 /// Run ciabatta's static dependency analysis and fold the resulting graph into
209 /// the knowledge graph (the brain), so the assistant — and the `deps` tool —
210 /// can traverse third-party and cross-package dependencies. Returns a one-line
211 /// summary of what was captured. Shared by burn-in and the `/analyze` command.
212 pub async fn scan_dependencies(
213     assistant: &Assistant,
214     root: &Path,
215     events: &mpsc::Sender<AiEvent>,
216 ) -> Result<String> {
217     use crate::analyze::Category;
218 
219     let _ = events
220         .send(AiEvent::Status("scanning dependencies (static analysis)…".to_string()))
221         .await;
222 
223     // Run the (synchronous) analysis off the async worker so a large repo scan
224     // doesn't stall other tasks on this runtime thread.
225     let root = root.to_path_buf();
226     let config = assistant.toolbox.config.clone();
227     let graph = tokio::task::spawn_blocking(move || {
228         crate::analyze::analyze_quiet(&root, &config, &crate::analyze::RequirementInputs::default())
229     })
230     .await
231     .context("dependency analysis task panicked")??;
232 
233     let internal = graph
234         .nodes
235         .iter()
236         .filter(|n| n.category == Category::Internal && n.id != "int:root")
237         .count();
238     let external = graph.nodes.iter().filter(|n| n.category == Category::External).count();
239     let publish = graph.nodes.iter().filter(|n| n.category == Category::Publish).count();
240     let files = graph.files.len();
241 
242     assistant.brain.set_dependencies(graph)?;
243 
244     Ok(format!(
245         "static analysis added to the mind map: {internal} internal package(s), {external} \
246          external dependency(ies), {publish} publish point(s), {files} manifest/source file(s) \
247          scanned — traverse them with the `deps` tool"
248     ))
249 }
