251 /// Ask the model to name the project's architecture parts from the file tree
252 /// and manifest heads. Returns `(name, description)` pairs.
253 async fn survey(assistant: &Assistant, root: &Path, files: &[String]) -> Result<Vec<(String, String)>> {
254     let mut prompt = String::from("Project file tree (truncated):\n");
255     for f in files.iter().take(SURVEY_PATHS) {
256         prompt.push_str(f);
257         prompt.push('\n');
258     }
259     for manifest in [
260         "README.md",
261         "Cargo.toml",
262         "package.json",
263         "pyproject.toml",
264         "go.mod",
265         "pom.xml",
266     ] {
267         if let Some(head) = file_head(&root.join(manifest)) {
268             prompt.push_str(&format!("\n--- {manifest} (head) ---\n{head}\n"));
269         }
270     }
271     prompt.push_str(
272         "\nName the architecture parts of this software: the 3–10 major areas a \
273          developer would recognize (e.g. 'cli', 'auth', 'deploy', 'frontend'). \
274          Use short, lowercase, reusable names. Reply with ONLY a JSON array: \
275          [{\"name\": \"...\", \"description\": \"one line on what it is\"}]",
276     );
277 
278     let system = "You analyze codebases and answer with strict JSON only — no prose, \
279                   no markdown fences.";
280     let turn = assistant
281         .provider
282         .chat(system, &[Turn::User(prompt)], &[])
283         .await?;
284     let items = extract_json_array(&turn.text)
285         .context("the model did not return a JSON array of architectures")?;
286 
287     let mut out = Vec::new();
288     for item in items {
289         let name = item["name"].as_str().unwrap_or("").trim().to_lowercase();
290         if name.is_empty() {
291             continue;
292         }
293         let description = item["description"].as_str().unwrap_or("").trim().to_string();
294         out.push((name, description));
295     }
296     anyhow::ensure!(!out.is_empty(), "the survey returned no architectures");
297     Ok(out)
298 }
299 
300 /// Tag one batch of files: send their heads, apply (or queue) the returned
301 /// tags. Returns how many files were tagged.
302 async fn tag_batch(
303     assistant: &Assistant,
304     root: &Path,
305     batch: &[String],
306     review: bool,
307 ) -> Result<usize> {
308     let known: Vec<String> = assistant.brain.graph_json()["nodes"]
309         .as_array()
310         .into_iter()
311         .flatten()
312         .filter(|n| n["kind"] == "architecture")
313         .filter_map(|n| n["label"].as_str().map(str::to_string))
314         .collect();
315 
316     let mut prompt = format!(
317         "Known architectures: [{}]. Prefer these tags; introduce a new lowercase \
318          tag only when a file clearly belongs to an area not listed.\n\n",
319         known.join(", ")
320     );
321     for path in batch {
322         let head = file_head(&root.join(path)).unwrap_or_default();
323         prompt.push_str(&format!("--- {path} ---\n{head}\n\n"));
324     }
325     prompt.push_str(
326         "Tag each file with the architecture(s) it belongs to (1–3 tags per file; \
327          a file can belong to several). Reply with ONLY a JSON array: \
328          [{\"path\": \"...\", \"tags\": [\"...\"], \"reason\": \"one short line\"}]",
329     );
330 
331     let system = "You classify source files into a codebase's architecture areas and \
332                   answer with strict JSON only — no prose, no markdown fences.";
333     let turn = assistant
334         .provider
335         .chat(system, &[Turn::User(prompt)], &[])
336         .await?;
337     let items = extract_json_array(&turn.text)
338         .context("the model did not return a JSON array of file tags")?;
339 
340     let mut tagged = 0;
341     for item in items {
342         let Some(path) = item["path"].as_str() else { continue };
343         // Only accept paths we actually sent — the map must never gain
344         // entries the model invented.
345         if !batch.iter().any(|b| b == path) {
346             continue;
347         }
348         let tags: Vec<String> = item["tags"]
349             .as_array()
350             .into_iter()
351             .flatten()
352             .filter_map(|t| t.as_str().map(str::to_string))
353             .take(3)
354             .collect();
355         if tags.is_empty() {
356             continue;
357         }
358         let reason = item["reason"].as_str().unwrap_or("");
359         let applied = if review {
360             assistant.brain.propose_tags(path, &tags, reason)
361         } else {
362             assistant.brain.install_tags(path, &tags)
363         };
364         if applied.is_ok() {
365             tagged += 1;
366         }
367     }
368     Ok(tagged)
369 }
