371 // ─── helpers ─────────────────────────────────────────────────────────────────
372 
373 /// Extensions (and exact names) worth showing the model during burn-in.
374 const SOURCE_EXTS: &[&str] = &[
375     "rs", "go", "py", "js", "jsx", "ts", "tsx", "mjs", "cjs", "java", "kt", "kts", "rb", "php",
376     "c", "h", "cc", "cpp", "hpp", "cs", "swift", "m", "scala", "sh", "bash", "zsh", "ps1", "sql",
377     "html", "css", "scss", "vue", "svelte", "toml", "yaml", "yml", "ini", "cfg", "conf", "md",
378     "proto", "tf",
379 ];
380 const SOURCE_NAMES: &[&str] = &["Dockerfile", "Makefile", "Justfile", "Rakefile"];
381 
382 /// The project's analyzable source files, in walk order.
383 fn source_files(root: &Path) -> Vec<String> {
384     tools::project_files(root)
385         .into_iter()
386         .filter(|p| {
387             let name = p.rsplit('/').next().unwrap_or(p);
388             if name.ends_with(".lock") || name.ends_with("-lock.json") || name.ends_with(".min.js")
389             {
390                 return false;
391             }
392             if SOURCE_NAMES.contains(&name) {
393                 return true;
394             }
395             name.rsplit_once('.')
396                 .map(|(_, ext)| SOURCE_EXTS.contains(&ext.to_lowercase().as_str()))
397                 .unwrap_or(false)
398         })
399         .collect()
400 }
401 
402 /// The first lines of a file (bounded in bytes and lines); `None` when the
403 /// file can't be read or is binary-ish.
404 fn file_head(path: &Path) -> Option<String> {
405     let mut buf = vec![0u8; HEAD_BYTES];
406     let mut file = std::fs::File::open(path).ok()?;
407     let n = file.read(&mut buf).ok()?;
408     buf.truncate(n);
409     if buf.contains(&0) {
410         return None; // binary
411     }
412     let text = String::from_utf8_lossy(&buf);
413     let mut head: Vec<&str> = text.lines().take(HEAD_LINES).collect();
414     // A byte-bounded read usually cuts the last line mid-way; drop it.
415     if n == HEAD_BYTES && head.len() > 1 {
416         head.pop();
417     }
418     Some(head.join("\n"))
419 }
420 
421 /// Pull the first JSON array out of a model reply, tolerating markdown fences
422 /// and surrounding prose.
423 fn extract_json_array(text: &str) -> Option<Vec<Value>> {
424     let start = text.find('[')?;
425     let end = text.rfind(']')?;
426     if end <= start {
427         return None;
428     }
429     serde_json::from_str::<Value>(&text[start..=end])
430         .ok()?
431         .as_array()
432         .cloned()
433 }
