435 #[cfg(test)]
436 mod tests {
437     use super::extract_json_array;
438 
439     #[test]
440     fn extracts_array_from_fenced_and_prosey_replies() {
441         let fenced = "Here you go:\n```json\n[{\"path\": \"a.rs\", \"tags\": [\"cli\"]}]\n```";
442         let items = extract_json_array(fenced).unwrap();
443         assert_eq!(items[0]["path"], "a.rs");
444 
445         let bare = "[{\"name\": \"auth\", \"description\": \"login\"}]";
446         assert_eq!(extract_json_array(bare).unwrap().len(), 1);
447 
448         assert!(extract_json_array("no json here").is_none());
449     }
450 }

    1 //! `ciabatta ai` — an AI assistant that learns your codebase.
    2 //!
    3 //! The assistant is a small daemon plus two front ends:
    4 //!
    5 //!   * an HTTP server (the "AI assistant" daemon) that renders the live
    6 //!     architecture mind map in the browser and exposes a JSON API
    7 //!   * a Ratatui chat TUI (the default way to talk to it)
    8 //!   * `ciabatta ai ask "..."` for one-shot questions from the shell
    9 //!
   10 //! As it works, the assistant tags files with architecture labels (pending
   11 //! your confirmation), builds a file→architecture map whose path scores grow
   12 //! with use, and keeps a 1–100 confidence score trained by your feedback —
   13 //! low scores behave like a junior dev, high scores like a senior dev. All of
   14 //! that state lives in `.ciabatta/ai/brain.json`.
   15 
   16 pub mod brain;
   17 pub mod burnin;
   18 pub mod compaction;
   19 pub mod edit;
   20 pub mod pdf;
   21 pub mod jobs;
   22 pub mod provider;
   23 pub mod server;
   24 pub mod session;
   25 pub mod tools;
   26 pub mod tui;
   27 
   28 use std::io::Write as _;
   29 use std::path::Path;
   30 use std::sync::Arc;
   31 
   32 use anyhow::{Context, Result};
   33 use tokio::sync::mpsc;
   34 
   35 use crate::config::{AiConfig, CIABATTA_DIR, CONFIG_FILE, CiabattaConfig};
   36 use brain::Brain;
   37 use provider::{Provider, Turn};
   38 use session::Conversation;
   39 use tools::ToolBox;
   40 
   41 /// Progress events emitted while the agent loop runs, consumed by whichever
   42 /// front end is active (TUI, CLI, or the HTTP API).
   43 #[derive(Debug, Clone)]
   44 pub enum AiEvent {
   45     /// A tool is being executed (one line, already human-readable).
   46     Status(String),
   47     /// The assistant proposed a code change (diff included), for the front
   48     /// end to display — and, in edit mode, to collect the user's verdict on.
   49     Suggestion(tools::ChangeSuggestion),
   50     /// The assistant's working plan changed (the full checklist), for the front
   51     /// end to render live progress on a multi-step task.
   52     Plan(Vec<tools::PlanItem>),
   53     /// The final answer for the current question.
   54     Answer(String),
   55     /// The loop failed.
   56     Error(String),
   57 }
   58 
   59 /// How much freedom the assistant has to change code.
   60 #[derive(Debug, Clone, Copy, PartialEq, Eq, Default)]
   61 pub enum Mode {
   62     /// Research only: no change proposals; answers end in a concrete plan.
   63     Plan,
   64     /// Changes are proposed as diffs and wait for the user to accept each one.
   65     #[default]
   66     Edit,
   67     /// Proposed changes are written to the working tree immediately.
   68     AutoAccept,
   69 }
   70 
   71 impl Mode {
   72     pub fn label(self) -> &'static str {
   73         match self {
   74             Mode::Plan => "plan",
   75             Mode::Edit => "edit",
   76             Mode::AutoAccept => "auto-accept",
   77         }
   78     }
   79 
   80     /// The next mode in the Shift-Tab cycle: plan → edit → auto-accept → plan.
   81     pub fn next(self) -> Self {
   82         match self {
   83             Mode::Plan => Mode::Edit,
   84             Mode::Edit => Mode::AutoAccept,
   85             Mode::AutoAccept => Mode::Plan,
   86         }
   87     }
   88 
   89     pub fn parse(s: &str) -> Result<Self> {
   90         match s.trim().to_lowercase().as_str() {
   91             "plan" => Ok(Mode::Plan),
   92             "edit" => Ok(Mode::Edit),
   93             "auto" | "auto-accept" | "autoaccept" => Ok(Mode::AutoAccept),
   94             other => anyhow::bail!("unknown mode '{other}' (expected plan, edit, or auto)"),
   95         }
   96     }
   97 }
   98 
   99 /// The assistant: a provider, its tools, and the shared brain.
  100 pub struct Assistant {
  101     pub provider: Provider,
  102     pub toolbox: Arc<ToolBox>,
  103     pub brain: Arc<Brain>,
  104     /// The current conversation, persisted to `.ciabatta/ai/conversations/`
  105     /// after every answer so it can be resumed later.
  106     conversation: tokio::sync::Mutex<Conversation>,
  107     /// One line on what the assistant is doing right now (burn-in progress
  108     /// etc.), surfaced live on the mind-map page's status pill.
  109     activity: std::sync::Mutex<Option<String>>,
  110 }
  111 
  112 /// Cap on model⇄tool round trips per question, so a confused model can't spin.
  113 const MAX_TOOL_ROUNDS: usize = 20;
  114 
  115 /// System prompt for generating a short conversation title (adapted from
  116 /// opencode). The model must reply with only the title, one line.
  117 const TITLE_SYSTEM: &str = "You generate a short title for a coding conversation, to help the user \
  118     find it later. Output ONLY the title: a single line, at most 50 characters, no quotes, no \
  119     trailing punctuation, no explanation. Focus on what the user wants to do. Keep filenames, \
  120     technical terms, and numbers exact. Never mention tools. Always output something meaningful.";
  121 
  122 impl Assistant {
  123     pub fn new(root: &Path, config: &CiabattaConfig) -> Result<Arc<Self>> {
  124         Self::with_conversation(root, config, Conversation::new(root))
  125     }
  126 
  127     /// Build an assistant that continues an existing conversation.
  128     pub fn with_conversation(
  129         root: &Path,
  130         config: &CiabattaConfig,
  131         conversation: Conversation,
  132     ) -> Result<Arc<Self>> {
  133         let ai_cfg = config.ai.clone().unwrap_or_default();
  134         let provider = Provider::from_config(&ai_cfg)?;
  135         let brain = Arc::new(Brain::open(root)?);
  136         let toolbox = Arc::new(ToolBox::new(
  137             root.to_path_buf(),
  138             brain.clone(),
  139             config.clone(),
  140         ));
  141         Ok(Arc::new(Self {
  142             provider,
  143             toolbox,
  144             brain,
  145             conversation: tokio::sync::Mutex::new(conversation),
  146             activity: std::sync::Mutex::new(None),
  147         }))
  148     }
  149 
  150     /// The conversation transcript so far (a clone of its turns), for a front
  151     /// end resuming a session to replay onto the screen.
  152     pub async fn transcript(&self) -> Vec<Turn> {
  153         self.conversation.lock().await.turns.clone()
  154     }
  155 
  156     /// The id the current conversation persists under.
  157     pub async fn conversation_id(&self) -> String {
  158         self.conversation.lock().await.id.clone()
  159     }
  160 
  161     /// Abandon the current conversation and start a fresh one, keeping the same
  162     /// brain and mind map. Returns the new conversation id. Used by `/new`.
  163     pub async fn start_new_conversation(&self) -> String {
  164         let mut conv = self.conversation.lock().await;
  165         *conv = Conversation::new(&self.toolbox.root);
  166         conv.id.clone()
  167     }
  168 
  169     /// The current working mode (plan / edit / auto-accept).
  170     pub fn mode(&self) -> Mode {
  171         self.toolbox.mode()
  172     }
  173 
  174     /// Switch the working mode; takes effect on the next model round.
  175     pub fn set_mode(&self, mode: Mode) {
  176         self.toolbox.set_mode(mode);
  177     }
  178 
  179     /// Set (or clear) the live activity line shown on the mind-map page.
