  260     /// Answer one question, streaming progress over `events`. Tool calls are
  261     /// executed locally between model rounds until the model stops calling
  262     /// tools. The final answer is both sent as an event and returned.
  263     pub async fn ask(&self, question: &str, events: mpsc::Sender<AiEvent>) -> Result<String> {
  264         self.toolbox.reset_touched();
  265         let specs = self.toolbox.specs();
  266 
  267         let mut conversation = self.conversation.lock().await;
  268         let history = &mut conversation.turns;
  269         history.push(Turn::User(question.to_string()));
  270 
  271         // Keep long sessions inside the context window: fold older turns into a
  272         // summary before we start spending model rounds on this question.
  273         if let Some(note) = compaction::maybe_compact(&self.provider, history).await {
  274             let _ = events.send(AiEvent::Status(note)).await;
  275         }
  276 
  277         let mut answer = String::new();
  278         for round in 0..MAX_TOOL_ROUNDS {
  279             let turn = match self.provider.chat(&self.system_prompt(), history, &specs).await {
  280                 Ok(t) => t,
  281                 Err(e) => {
  282                     // Drop the failed exchange so the session stays usable.
  283                     history.pop();
  284                     // `{:#}` walks the whole context chain, so the UI shows the
  285                     // underlying cause (timeout, refused connection, bad body)
  286                     // rather than just a generic "request failed".
  287                     let _ = events.send(AiEvent::Error(format!("{e:#}"))).await;
  288                     return Err(e);
  289                 }
  290             };
  291 
  292             if turn.refused || turn.tool_calls.is_empty() {
  293                 answer = turn.text.clone();
  294                 history.push(Turn::Assistant(turn));
  295                 break;
  296             }
  297 
  298             let calls = turn.tool_calls.clone();
  299             history.push(Turn::Assistant(turn));
  300 
  301             let changes_before = self.toolbox.changes_len();
  302             for call in &calls {
  303                 let _ = events.send(AiEvent::Status(ToolBox::describe(call))).await;
  304             }
  305             // Independent read-only calls in one round can run together; anything
  306             // that mutates state (edits, tags, the plan, the sandbox) stays
  307             // sequential so ordering and diffs are deterministic.
  308             let results = if calls.len() > 1 && calls.iter().all(|c| ToolBox::is_read_only(&c.name)) {
  309                 futures::future::join_all(calls.iter().map(|c| self.toolbox.execute(c))).await
  310             } else {
  311                 let mut results = Vec::with_capacity(calls.len());
  312                 for call in &calls {
  313                     results.push(self.toolbox.execute(call).await);
  314                 }
  315                 results
  316             };
  317             // Surface any change proposals this round produced, diff and all.
  318             for suggestion in self.toolbox.changes_since(changes_before) {
  319                 let _ = events.send(AiEvent::Suggestion(suggestion)).await;
  320             }
  321             // If the plan changed this round, push the updated checklist.
  322             if calls.iter().any(|c| c.name == "update_plan") {
  323                 let _ = events.send(AiEvent::Plan(self.toolbox.plan())).await;
  324             }
  325             history.push(Turn::ToolResults(results));
  326 
  327             if round == MAX_TOOL_ROUNDS - 1 {
  328                 answer = "I hit the tool-call limit before finishing — try narrowing the \
  329                           question."
  330                     .to_string();
  331             }
  332         }
  333 
  334         let _ = self.brain.record_interaction();
  335         let _ = events.send(AiEvent::Answer(answer.clone())).await;
  336 
  337         // On the first exchange, generate a concise title so the conversation is
  338         // easy to find in `ciabatta ai resume`. Best-effort: a failure just
  339         // leaves the fallback (first user line) that `save` derives.
  340         let is_first = conversation
  341             .turns
  342             .iter()
  343             .filter(|t| matches!(t, Turn::User(_)))
  344             .count()
  345             == 1;
  346         if is_first
  347             && conversation.title.is_empty()
  348             && !answer.is_empty()
  349             && let Some(title) = self.generate_title(question).await
  350         {
  351             conversation.title = title;
  352         }
  353 
  354         // Persist the whole exchange so the session can be resumed later.
  355         if let Err(e) = conversation.save() {
  356             tracing::debug!("failed to save conversation: {e}");
  357         }
  358         Ok(answer)
  359     }
