  361     /// Ask the model for a short title summarizing the opening question.
  362     /// Returns `None` on any error or an empty result.
  363     async fn generate_title(&self, first_question: &str) -> Option<String> {
  364         let prompt: String = first_question.chars().take(2000).collect();
  365         let turn = Turn::User(prompt);
  366         let reply = self.provider.chat(TITLE_SYSTEM, &[turn], &[]).await.ok()?;
  367         let line = reply.text.lines().find(|l| !l.trim().is_empty())?;
  368         let title: String = line.trim().trim_matches('"').chars().take(60).collect();
  369         (!title.is_empty()).then_some(title)
  370     }
