 24 /// Where a job is in its lifecycle.
 25 #[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
 26 #[serde(rename_all = "lowercase")]
 27 pub enum JobStatus {
 28     Queued,
 29     Running,
 30     Done,
 31     Failed,
 32 }
 33 
 34 impl JobStatus {
 35     pub fn label(self) -> &'static str {
 36         match self {
 37             JobStatus::Queued => "queued",
 38             JobStatus::Running => "running",
 39             JobStatus::Done => "done",
 40             JobStatus::Failed => "failed",
 41         }
 42     }
 43 }
 44 
 45 /// One background task and everything it produced.
 46 #[derive(Debug, Clone, Serialize, Deserialize)]
 47 pub struct Job {
 48     pub id: u64,
 49     pub prompt: String,
 50     /// Where the job came from, e.g. "manual", "gui", or "todo:3".
 51     pub source: String,
 52     pub status: JobStatus,
 53     pub created_at: String,
 54     #[serde(default)]
 55     pub started_at: Option<String>,
 56     #[serde(default)]
 57     pub finished_at: Option<String>,
 58     /// Human-readable tool steps the agent took.
 59     #[serde(default)]
 60     pub steps: Vec<String>,
 61     /// Files the job changed (auto-accepted while running).
 62     #[serde(default)]
 63     pub changed_files: Vec<String>,
 64     #[serde(default)]
 65     pub answer: Option<String>,
 66     #[serde(default)]
 67     pub error: Option<String>,
 68     /// The saved conversation this job's transcript lives in, for resuming.
 69     #[serde(default)]
 70     pub conversation_id: Option<String>,
 71 }
 72 
 73 /// The background-job runner: a persisted queue plus the project context needed
 74 /// to spin up a fresh assistant per job.
 75 pub struct Jobs {
 76     root: PathBuf,
 77     config: CiabattaConfig,
 78     path: PathBuf,
 79     inner: Mutex<Vec<Job>>,
 80     seq: AtomicU64,
 81 }
 82 
 83 impl Jobs {
 84     /// Open (or create) the job store under `.ciabatta/ai/jobs.json`.
 85     pub fn open(root: &std::path::Path, config: &CiabattaConfig) -> Result<std::sync::Arc<Self>> {
 86         let dir = root.join(crate::config::CIABATTA_DIR).join("ai");
 87         std::fs::create_dir_all(&dir)
 88             .with_context(|| format!("Failed to create {}", dir.display()))?;
 89         let path = dir.join("jobs.json");
 90         let jobs = match std::fs::read_to_string(&path) {
 91             Ok(s) if s.trim().is_empty() => Vec::new(),
 92             Ok(s) => serde_json::from_str(&s)
 93                 .with_context(|| format!("Failed to parse {}", path.display()))?,
 94             Err(e) if e.kind() == std::io::ErrorKind::NotFound => Vec::new(),
 95             Err(e) => return Err(e).with_context(|| format!("Failed to read {}", path.display())),
 96         };
 97         Ok(std::sync::Arc::new(Self {
 98             root: root.to_path_buf(),
 99             config: config.clone(),
100             path,
101             inner: Mutex::new(jobs),
102             seq: AtomicU64::new(1),
103         }))
104     }
105 
106     /// Change counter, bumped on every mutation so the GUI can poll cheaply.
107     pub fn seq(&self) -> u64 {
108         self.seq.load(Ordering::Relaxed)
109     }
110 
111     /// A snapshot of every job, newest first.
112     pub fn list(&self) -> Vec<Job> {
113         let mut jobs = self.inner.lock().unwrap().clone();
114         jobs.sort_by(|a, b| b.id.cmp(&a.id));
115         jobs
116     }
117 
118     /// The jobs as a JSON payload for the daemon API.
119     pub fn snapshot_json(&self) -> Value {
120         json!({ "seq": self.seq(), "jobs": self.list() })
121     }
122 
123     /// Queue a task and start it in the background, returning its id. The work
124     /// happens on a spawned task; poll [`Self::list`] for progress.
125     pub fn ship(self: &std::sync::Arc<Self>, prompt: &str, source: &str) -> Result<u64> {
126         let id = self.enqueue(prompt, source)?;
127         let this = self.clone();
128         let prompt = prompt.to_string();
129         tokio::spawn(async move {
130             this.execute(id, &prompt).await;
131         });
132         Ok(id)
133     }
134 
135     /// Queue a task and run it to completion (used by the CLI, which then prints
136     /// the result). Returns the finished job record.
137     pub async fn ship_and_wait(self: &std::sync::Arc<Self>, prompt: &str, source: &str) -> Result<Job> {
138         let id = self.enqueue(prompt, source)?;
139         self.execute(id, prompt).await;
140         self.get(id).context("job vanished after completion")
141     }
142 
143     /// A single job by id.
144     pub fn get(&self, id: u64) -> Option<Job> {
145         self.inner.lock().unwrap().iter().find(|j| j.id == id).cloned()
146     }
147 
148     /// Create a queued job record and persist it.
149     fn enqueue(&self, prompt: &str, source: &str) -> Result<u64> {
150         let prompt = prompt.trim();
151         anyhow::ensure!(!prompt.is_empty(), "cannot ship an empty task to the AI");
152         let mut jobs = self.inner.lock().unwrap();
153         let id = jobs.iter().map(|j| j.id).max().unwrap_or(0) + 1;
154         jobs.push(Job {
155             id,
156             prompt: prompt.to_string(),
157             source: source.to_string(),
158             status: JobStatus::Queued,
159             created_at: now(),
160             started_at: None,
161             finished_at: None,
162             steps: Vec::new(),
163             changed_files: Vec::new(),
164             answer: None,
165             error: None,
166             conversation_id: None,
167         });
168         persist(&self.path, &jobs);
169         self.seq.fetch_add(1, Ordering::Relaxed);
170         Ok(id)
171     }
172 
173     /// Run one job: a fresh auto-accept assistant works the prompt to a finish,
174     /// and the outcome (answer or error, steps, changed files) is recorded.
175     async fn execute(&self, id: u64, prompt: &str) {
176         self.update(id, |j| {
177             j.status = JobStatus::Running;
178             j.started_at = Some(now());
179         });
180 
181         let assistant = match Assistant::new(&self.root, &self.config) {
182             Ok(a) => a,
183             Err(e) => {
184                 self.update(id, |j| {
185                     j.status = JobStatus::Failed;
186                     j.finished_at = Some(now());
187                     j.error = Some(e.to_string());
188                 });
189                 return;
190             }
191         };
192         // Behind-the-scenes work should actually complete, so changes land
193         // without waiting for interactive approval.
194         assistant.set_mode(Mode::AutoAccept);
195 
196         let (tx, mut rx) = mpsc::channel::<AiEvent>(64);
197         let collector = tokio::spawn(async move {
198             let mut steps = Vec::new();
199             let mut changed = Vec::new();
200             while let Some(ev) = rx.recv().await {
201                 match ev {
202                     AiEvent::Status(s) => steps.push(s),
203                     AiEvent::Suggestion(c) => changed.push(c.file),
204                     _ => {}
205                 }
206             }
207             (steps, changed)
208         });
209 
210         let result = assistant.ask(prompt, tx).await;
211         let (steps, changed) = collector.await.unwrap_or_default();
212         let conversation_id = assistant.conversation_id().await;
213 
214         self.update(id, |j| {
215             j.steps = steps.clone();
216             j.changed_files = changed.clone();
217             j.conversation_id = Some(conversation_id.clone());
218             j.finished_at = Some(now());
219             match &result {
220                 Ok(answer) => {
221                     j.status = JobStatus::Done;
222                     j.answer = Some(answer.clone());
223                 }
224                 Err(e) => {
225                     j.status = JobStatus::Failed;
226                     // Full context chain, so a failed job records *why* (timeout,
227                     // refused connection, …) not just a generic message.
228                     j.error = Some(format!("{e:#}"));
229                 }
230             }
231         });
232     }
233 
234     /// Apply a mutation to one job, persist, and bump the sequence.
235     fn update(&self, id: u64, f: impl FnOnce(&mut Job)) {
236         let mut jobs = self.inner.lock().unwrap();
237         if let Some(j) = jobs.iter_mut().find(|j| j.id == id) {
238             f(j);
239         }
240         persist(&self.path, &jobs);
241         self.seq.fetch_add(1, Ordering::Relaxed);
242     }
243 }
244 
245 /// Persist the job list, logging (not surfacing) any write error — a failed
246 /// save shouldn't abort a running job.
247 fn persist(path: &PathBuf, jobs: &[Job]) {
248     match serde_json::to_string_pretty(jobs) {
249         Ok(json) => {
250             if let Err(e) = std::fs::write(path, json) {
251                 tracing::debug!("failed to persist jobs to {}: {e}", path.display());
252             }
253         }
254         Err(e) => tracing::debug!("failed to serialize jobs: {e}"),
255     }
256 }
257 
258 fn now() -> String {
