196     /// Apply (write to the working tree) or reject the oldest pending change
197     /// for `file`, returning its updated record.
198     pub fn resolve_change(&self, file: &str, accept: bool) -> Result<ChangeSuggestion> {
199         let mut changes = self.changes.lock().unwrap();
200         let change = changes
201             .iter_mut()
202             .find(|c| c.state == ChangeState::Pending && c.file == file)
203             .with_context(|| format!("no pending change for '{file}'"))?;
204         if accept {
205             if let Some(parent) = change.target.parent() {
206                 std::fs::create_dir_all(parent)?;
207             }
208             std::fs::copy(&change.proposed, &change.target)
209                 .with_context(|| format!("failed to write '{}'", change.file))?;
210             change.state = ChangeState::Applied;
211         } else {
212             change.state = ChangeState::Rejected;
213         }
214         Ok(change.clone())
215     }
