217     /// Undo the most recently applied change, restoring the file from its
218     /// pre-change snapshot (or deleting it if the change had created it).
219     /// Returns the reverted record, or `None` if nothing is applied.
220     pub fn revert_last_applied(&self) -> Result<Option<ChangeSuggestion>> {
221         let mut changes = self.changes.lock().unwrap();
222         let Some(change) = changes.iter_mut().rev().find(|c| c.state == ChangeState::Applied) else {
223             return Ok(None);
224         };
225         if change.created {
226             // The change made a new file; undoing it removes the file.
227             match std::fs::remove_file(&change.target) {
228                 Ok(()) => {}
229                 Err(e) if e.kind() == std::io::ErrorKind::NotFound => {}
230                 Err(e) => return Err(e).with_context(|| format!("failed to remove '{}'", change.file)),
231             }
232         } else {
233             std::fs::copy(&change.original, &change.target)
234                 .with_context(|| format!("failed to restore '{}'", change.file))?;
235         }
236         change.state = ChangeState::Reverted;
237         Ok(Some(change.clone()))
238     }
