fn sandbox_images(&self) -> Vec<String> {
    self.config
        .ai
        .as_ref()
        .map(|a| a.images.clone())
        .unwrap_or_default()
}

/// The command that proves the project still builds/tests, used by the
/// agent loop's verification gate. An explicit `verify` under `[ai]` wins;
/// an empty string disables the gate; otherwise a sensible default is
/// auto-detected from the project's manifests. `None` means "no gate".
pub fn verify_command(&self) -> Option<String> {
    if let Some(ai) = self.config.ai.as_ref()
        && let Some(cmd) = ai.verify.as_ref()
    {
        let cmd = cmd.trim();
        // An explicit empty string is the user opting out of the gate.
        return (!cmd.is_empty()).then(|| cmd.to_string());
    }
    self.autodetect_verify()
}

/// Guess a build/test command from the manifests present at the project
/// root, so the verification gate works out of the box for common stacks.
fn autodetect_verify(&self) -> Option<String> {
    let has = |name: &str| self.root.join(name).exists();
    if has("Cargo.toml") {
        Some("cargo build".to_string())
    } else if has("package.json") {
        // `build` is the near-universal script name; `--if-present` keeps
        // this from failing on packages that don't define one.
        Some("npm run build --if-present".to_string())
    } else if has("go.mod") {
        Some("go build ./...".to_string())
    } else if has("pyproject.toml") || has("setup.py") {
        Some("python -m compileall -q .".to_string())
    } else if has("Makefile") {
        Some("make".to_string())
    } else {
        None
    }
}

/// Run the verification command from the project root, returning whether it
/// passed and its (clipped) combined output. Shares the shell-out path with
/// the `run_command` tool.
pub async fn run_verify(&self, command: &str) -> (bool, String) {
    match self.shell(command).await {
        Ok((success, output)) => (success, output),
        Err(e) => (false, format!("verification command failed to run: {e:#}")),
    }
}

async fn run_command(&self, args: &Value) -> Result<String> {
    let command = args["command"]
        .as_str()
        .context("run_command needs a 'command'")?;
    let (_success, output) = self.shell(command).await?;
    Ok(output)
}

/// Run a shell command from the project root via `sh -c`, capping runtime so
/// a hung build/test can't wedge the whole agent loop. Returns whether the
/// command exited successfully and its (clipped) combined stdout/stderr
/// output, with the exit status appended. Shared by `run_command` and the
/// loop's verification gate (`run_verify`).
async fn shell(&self, command: &str) -> Result<(bool, String)> {
    let fut = tokio::process::Command::new("sh")
        .arg("-c")
        .arg(command)
        .current_dir(&self.root)
        .output();
    // Cap runtime so a hung build/test can't wedge the whole agent loop.
    let output = match tokio::time::timeout(std::time::Duration::from_secs(300), fut).await {
        Ok(res) => res.with_context(|| format!("failed to run: {command}"))?,
        Err(_) => bail!("command timed out after 300s: {command}"),
    };

    let mut out = String::new();
    out.push_str(&String::from_utf8_lossy(&output.stdout));
    let stderr = String::from_utf8_lossy(&output.stderr);
    if !stderr.trim().is_empty() {
        out.push_str("\n[stderr]\n");
        out.push_str(&stderr);
    }
    out.push_str(&format!("\n[exit status: {}]", output.status));
    Ok((output.status.success(), clip(&out, 16_000)))
}

